import copy
import numpy as np
import numpy.typing as npt
from rory.core.security.cryptosystem.liu import Liu
from rory.core.utils.constants import Constants
from rory.core.utils.utils import Utils
from rory.core.security.cryptosystem.FDHOpe import Fdhope
from option import Result,Ok,Err,Option,NONE,Some
from typing import Any,List,Tuple


"""
Description:
	Distributed skmeans algorithm.
	Divide skmeans into two parts. The first ends when client interaction is required. The second ends when the matrix S is zero.
"""
class DBSKMeans(object):

	"""
	Description:
		The skmeans algorithm is started up to where the decryption of the matrix S is required
	"""
	def run1(self,
		encrypted_matrix:npt.NDArray,
		UDM:npt.NDArray,
		status:int=Constants.ClusteringStatus.START, 
		k:int =3,
		m:int=3,
		Cent_j:Option[List[List[float]]] = NONE
	# **kwargs
	)->Result[
		Tuple[
			npt.NDArray,
			npt.NDArray,
			npt.NDArray,
			# List[List[float]],
			# List[List[float]],
			List[int]
		],
		Exception
	]:
		try:
			# status  = kwargs.get("status",Constants.ClusteringStatus.START)
			# k       = kwargs.get("k",3)
			# m       = kwargs.get("m",3)
			# D1      = kwargs.get("encryptedMatrix")
			encrypted_matrix_shape = Utils.getShapeOfMatrix(encrypted_matrix)
			a = encrypted_matrix_shape[1]
			# print("ATTRIBUTES",a)
			# U       = kwargs.get("UDM")
			# a       = kwargs.get("num_attributes",D1Shape[1])
			C_empty = Utils.empty_cluster(k = k)
			
			# Cuando va iniciando DBSKMeans 
			if( status == Constants.ClusteringStatus.START ):
				C              = list(map(lambda x:[encrypted_matrix[x].tolist()],list(range(0,k)))) #add the first k records of D to C
				
				populate_cluster_result= Utils.populateClusters(
					record_id         = k,
					UDM               = UDM,
					clusters          = C,
					ciphertext_matrix = encrypted_matrix,
				)
				if populate_cluster_result.is_err:
					return Err(populate_cluster_result.unwrap_err())
				_C,label_vector = populate_cluster_result.unwrap()

				Cent_i = [encrypted_matrix[i] for i in range(k)] # initializes the set of centroids with the first record in D
				calculate_centroids_result = Utils.calculateCentroids(
					clusters   = _C,
					k          = k,
					attributes = a,
					m          = m,
				)
				
				if calculate_centroids_result.is_err:
					return Err(calculate_centroids_result.unwrap_err())
				
				_Cent_j = calculate_centroids_result.unwrap()
		
				S1  = self.generateShifMatrix(
					k = k,
					m = m,
					a = a,
					previuos_centroids = Cent_i, 
					current_centroids  = _Cent_j
				)

				label_vector = Utils.fillLabelVector(
					label_vector = label_vector,
					k            = k
				)
				return Ok(
					(
						S1,
						np.array(Cent_i),
						np.array(_Cent_j),
						label_vector
					)
				)
			else:
				_Cent_j  = Cent_j.unwrap()
				populate_cluster_result:Result[Tuple[List[List[int]],List[int]],Exception] =  Utils.populateClusters(
					record_id = 0,
					UDM       = UDM,
					clusters  = C_empty,
					ciphertext_matrix = encrypted_matrix,
				)
				if populate_cluster_result.is_err:
					return Err(populate_cluster_result.unwrap_err())
				
				C,label_vector = populate_cluster_result.unwrap()
				Cent_i = copy.copy(_Cent_j) #Reasigna los elementos de cent_j a cent_i

				calculate_centroids_result = Utils.calculateCentroids(
					clusters   = C,
					k          = k,
					attributes = a,
					m          = m,
				)

				if calculate_centroids_result.is_err:
					return Err(calculate_centroids_result.unwrap_err())
				
				__Cent_j = calculate_centroids_result.unwrap()
				
				S1       = self.generateShifMatrix(
					previuos_centroids = Cent_i,
					current_centroids  = __Cent_j,
					k = k,
					m =m,
					a = a,
				)

				return  Ok(
					(
						S1,
						np.array(Cent_i),
						np.array(__Cent_j),
						label_vector
					)
				)
		except Exception as e:
			return Err(e)


	"""
	description:  Update UDM matrix.
		A UDM matrix is a 3D matrix containing distances between the attribute values in each record
		and the corresponding attribute values in all other records.
	attributes:
		U: Updatable distance matrix
		Cent_i: previous set of centroids
		Cent_j: next set of centroids
		m: number of attributes of SK
	"""
	def run_2(self,**kwargs):
		k      = kwargs.get("k",3)
		_U     = kwargs.get("UDM")
		U      = _U.tolist()
		a      = kwargs.get("attributes")
		_S     = kwargs.get("shiftMatrix")
		S      = _S.tolist()
		U1 = []
		for x in range(_U.shape[0]):
			U1.append([])
			for y in range(k):
				U1[x].append([])
				for z in range(a):
					U1[x][y].append([])
					if y > x: #Se revisa U completa.
						U1[x][y][z] = ((-U[y][x][z] + S[y][z])) #Suma de cada elemento de U con S
					else:
						U1[x][y][z] = (U[x][y][z] + S[y][z]) #Suma de cada elemento de U con S
		return np.array(U1)


	"""
	Description:
		Generate encrypted shift matrix.
	"""
	def generateShifMatrix(self,
	 		previuos_centroids:List[List[float]],
			current_centroids:List[List[float]],
			k:int,
			a:int,
			m:int=3,
	)->npt.NDArray:
		# Cent_i = kwargs.get("previous_centroids")
		# Cent_j = kwargs.get("current_centroids")
		# k      = kwargs.get("k",3)
		# m      = kwargs.get("m",3)
		# a      = kwargs.get("a",3)
		S1     = np.zeros((k,a,m)).tolist()
		for i in range(len(previuos_centroids)):
			for j in range(len(previuos_centroids[i])):
				S1[i][j] = Liu.subtract(
					ciphertext_1 = previuos_centroids[i][j], 
					ciphertext_2 = current_centroids[i][j]
					) #Resta con el esquema de Liu
		return np.array(S1)